import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const _=JSON.parse('{"title":"🌾 黃豆肥料成本與尿素影響深度報告","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆肥料成本與尿素影響深度報告.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆肥料成本與尿素影響深度報告.md"}'),h={name:"Deep32Q知識庫/產業洞察/黃豆研究/黃豆肥料成本與尿素影響深度報告.md"};function o(l,t,n,i,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="🌾-黃豆肥料成本與尿素影響深度報告" tabindex="-1">🌾 黃豆肥料成本與尿素影響深度報告 <a class="header-anchor" href="#🌾-黃豆肥料成本與尿素影響深度報告" aria-label="Permalink to &quot;🌾 黃豆肥料成本與尿素影響深度報告&quot;">​</a></h1><p><strong>報告日期：</strong> 2026-04-27 17:10 <strong>資料來源：</strong> USDA、CBOT、Trading Economics、IFA、中東局勢分析 <strong>歸檔路徑：</strong> /skills/NEW_Deep32Q/Deep32Q知識庫/產業洞察/黃豆研究/</p><hr><h2 id="一、肥料成本對黃豆種植的影響" tabindex="-1">一、肥料成本對黃豆種植的影響 <a class="header-anchor" href="#一、肥料成本對黃豆種植的影響" aria-label="Permalink to &quot;一、肥料成本對黃豆種植的影響&quot;">​</a></h2><h3 id="_1-1-黃豆種植成本結構" tabindex="-1">1.1 黃豆種植成本結構 <a class="header-anchor" href="#_1-1-黃豆種植成本結構" aria-label="Permalink to &quot;1.1 黃豆種植成本結構&quot;">​</a></h3><table tabindex="0"><thead><tr><th>項目</th><th>佔比</th><th>每英畝成本</th></tr></thead><tbody><tr><td>種子</td><td>8-12%</td><td>$60-80</td></tr><tr><td><strong>肥料</strong></td><td><strong>15-20%</strong></td><td><strong>$80-120</strong></td></tr><tr><td>農藥</td><td>8-12%</td><td>$50-80</td></tr><tr><td>人工</td><td>10-15%</td><td>$60-100</td></tr><tr><td>機械/設備</td><td>15-20%</td><td>$100-130</td></tr><tr><td>土地租金</td><td>25-30%</td><td>$150-200</td></tr><tr><td><strong>總成本</strong></td><td>100%</td><td><strong>$550-750</strong></td></tr></tbody></table><h3 id="_1-2-肥料價格敏感度" tabindex="-1">1.2 肥料價格敏感度 <a class="header-anchor" href="#_1-2-肥料價格敏感度" aria-label="Permalink to &quot;1.2 肥料價格敏感度&quot;">​</a></h3><table tabindex="0"><thead><tr><th>肥料漲幅</th><th>總成本影響</th><th>盈虧平衡價影響</th></tr></thead><tbody><tr><td>+10%</td><td>+1.8%</td><td>+$0.04-0.06/蒲式耳</td></tr><tr><td>+25%</td><td>+4.5%</td><td>+$0.10-0.15/蒲式耳</td></tr><tr><td>+50%</td><td>+9%</td><td>+$0.20-0.25/蒲式耳</td></tr><tr><td>+100%</td><td>+18%</td><td>+$0.40-0.50/蒲式耳</td></tr></tbody></table><h3 id="_1-3-盈虧平衡價格" tabindex="-1">1.3 盈虧平衡價格 <a class="header-anchor" href="#_1-3-盈虧平衡價格" aria-label="Permalink to &quot;1.3 盈虧平衡價格&quot;">​</a></h3><ul><li><strong>當前盈虧平衡價</strong>：$10.40-13.54/蒲式耳</li><li><strong>當前 CBOT 報價</strong>：~$11.66/蒲式耳</li><li><strong>結論</strong>：多數農民處於<strong>微利或虧損</strong>狀態</li></ul><hr><h2 id="二、尿素市場現況" tabindex="-1">二、尿素市場現況 <a class="header-anchor" href="#二、尿素市場現況" aria-label="Permalink to &quot;二、尿素市場現況&quot;">​</a></h2><h3 id="_2-1-價格走勢" tabindex="-1">2.1 價格走勢 <a class="header-anchor" href="#_2-1-價格走勢" aria-label="Permalink to &quot;2.1 價格走勢&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>數值</th></tr></thead><tbody><tr><td>當前尿素價格</td><td>$480-580/噸（FOB）</td></tr><tr><td>近期高點</td><td>~$650/噸（2025 年底）</td></tr><tr><td>歷史高點</td><td>$900+/噸（2022 年俄烏戰爭初期）</td></tr><tr><td>關鍵閾值</td><td><strong>$700/噸</strong></td></tr></tbody></table><h3 id="_2-2-全球供應格局" tabindex="-1">2.2 全球供應格局 <a class="header-anchor" href="#_2-2-全球供應格局" aria-label="Permalink to &quot;2.2 全球供應格局&quot;">​</a></h3><table tabindex="0"><thead><tr><th>國家</th><th>產量（M噸）</th><th>出口限制</th></tr></thead><tbody><tr><td>中國</td><td>~65</td><td>配額式管理</td></tr><tr><td>俄羅斯</td><td>~25</td><td>制裁影響</td></tr><tr><td>印度</td><td>~30</td><td>出口禁令</td></tr><tr><td>中東</td><td>~20</td><td>無限制（海運風險）</td></tr><tr><td>美國</td><td>~15</td><td>無限制</td></tr></tbody></table><h3 id="_2-3-中國出口政策演變" tabindex="-1">2.3 中國出口政策演變 <a class="header-anchor" href="#_2-3-中國出口政策演變" aria-label="Permalink to &quot;2.3 中國出口政策演變&quot;">​</a></h3><table tabindex="0"><thead><tr><th>時期</th><th>政策</th><th>影響</th></tr></thead><tbody><tr><td>2024</td><td>全面禁令</td><td>全球供給緊縮</td></tr><tr><td>2025/06</td><td>放寬（Bloomberg 報導）</td><td>國際價格承壓</td></tr><tr><td>2026</td><td>配額式管理</td><td>供大於求，政策穩定</td></tr><tr><td>未來</td><td>收緊機率僅 15%</td><td>短期穩定</td></tr></tbody></table><hr><h2 id="三、中東戰事影響" tabindex="-1">三、中東戰事影響 <a class="header-anchor" href="#三、中東戰事影響" aria-label="Permalink to &quot;三、中東戰事影響&quot;">​</a></h2><h3 id="_3-1-荷莫茲海峽風險" tabindex="-1">3.1 荷莫茲海峽風險 <a class="header-anchor" href="#_3-1-荷莫茲海峽風險" aria-label="Permalink to &quot;3.1 荷莫茲海峽風險&quot;">​</a></h3><ul><li>全球 <strong>20% 石油運輸</strong>通過荷莫茲海峽</li><li>中東尿素出口高度依賴海運</li><li>若封鎖 → 中東尿素出口中斷 → 全球供給缺口 <strong>~5-8%</strong></li></ul><h3 id="_3-2-中東尿素產能" tabindex="-1">3.2 中東尿素產能 <a class="header-anchor" href="#_3-2-中東尿素產能" aria-label="Permalink to &quot;3.2 中東尿素產能&quot;">​</a></h3><table tabindex="0"><thead><tr><th>國家</th><th>全球產量佔比</th><th>主要出口市場</th></tr></thead><tbody><tr><td>沙烏地阿拉伯</td><td>~8%</td><td>印度、東南亞</td></tr><tr><td>卡達</td><td>~5%</td><td>印度、東南亞</td></tr><tr><td>阿曼</td><td>~3%</td><td>印度、非洲</td></tr><tr><td><strong>合計</strong></td><td><strong>~16%</strong></td><td>亞洲為主</td></tr></tbody></table><h3 id="_3-3-戰事情境分析" tabindex="-1">3.3 戰事情境分析 <a class="header-anchor" href="#_3-3-戰事情境分析" aria-label="Permalink to &quot;3.3 戰事情境分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>情景</th><th>機率</th><th>尿素影響</th><th>黃豆影響</th></tr></thead><tbody><tr><td>低度衝突（現狀）</td><td>60%</td><td>+5-10%</td><td>+2-4%</td></tr><tr><td>海峽短暫封鎖</td><td>25%</td><td>+30-50%</td><td>+12-20%</td></tr><tr><td>全面戰爭</td><td>10%</td><td>+80-120%</td><td>+25-40%</td></tr><tr><td>停火協議</td><td>5%</td><td>-10-15%</td><td>-3-5%</td></tr></tbody></table><hr><h2 id="四、尿素對黃豆的傳導機制" tabindex="-1">四、尿素對黃豆的傳導機制 <a class="header-anchor" href="#四、尿素對黃豆的傳導機制" aria-label="Permalink to &quot;四、尿素對黃豆的傳導機制&quot;">​</a></h2><h3 id="_4-1-傳導鏈路" tabindex="-1">4.1 傳導鏈路 <a class="header-anchor" href="#_4-1-傳導鏈路" aria-label="Permalink to &quot;4.1 傳導鏈路&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>肥料成本↑ → 種植成本↑ → 種植意願↓ → 面積↓ → 供給↓ → 黃豆期貨↑</span></span>
<span class="line"><span>         ↓</span></span>
<span class="line"><span>       玉米更貴 → 農民轉種黃豆 → 黃豆供給↑ → 價格↓</span></span></code></pre></div><h3 id="_4-2-量化模型" tabindex="-1">4.2 量化模型 <a class="header-anchor" href="#_4-2-量化模型" aria-label="Permalink to &quot;4.2 量化模型&quot;">​</a></h3><ul><li><strong>傳導係數 α = 0.4-0.6</strong></li><li>尿素每升 10% → 黃豆期貨漲 4-6%</li><li>歷史相關性：尿素 vs CBOT 黃豆 +0.72~0.81</li><li>傳導滯後：6-12 個月</li></ul><h3 id="_4-3-黃豆固氮緩衝" tabindex="-1">4.3 黃豆固氮緩衝 <a class="header-anchor" href="#_4-3-黃豆固氮緩衝" aria-label="Permalink to &quot;4.3 黃豆固氮緩衝&quot;">​</a></h3><ul><li>黃豆有固氮能力，肥料漲價衝擊比玉米小</li><li>但間接效應（轉種）可能增加黃豆供給</li></ul><hr><h2 id="五、綜合投資建議" tabindex="-1">五、綜合投資建議 <a class="header-anchor" href="#五、綜合投資建議" aria-label="Permalink to &quot;五、綜合投資建議&quot;">​</a></h2><h3 id="_5-1-當前市場定位" tabindex="-1">5.1 當前市場定位 <a class="header-anchor" href="#_5-1-當前市場定位" aria-label="Permalink to &quot;5.1 當前市場定位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>維度</th><th>數值</th><th>判斷</th></tr></thead><tbody><tr><td>CBOT 報價</td><td>1,166 美分</td><td>區間中段</td></tr><tr><td>盈虧平衡價</td><td>1,040-1,354 美分</td><td>接近下緣</td></tr><tr><td>尿素價格</td><td>$480-580/噸</td><td>未達 $700 閾值</td></tr><tr><td>供需格局</td><td>偏鬆</td><td>巴西豐收+美國擴種</td></tr><tr><td>季節性</td><td>4-5 月</td><td>偏多（種植季）</td></tr></tbody></table><h3 id="_5-2-多空因子" tabindex="-1">5.2 多空因子 <a class="header-anchor" href="#_5-2-多空因子" aria-label="Permalink to &quot;5.2 多空因子&quot;">​</a></h3><table tabindex="0"><thead><tr><th>看多</th><th>看空</th></tr></thead><tbody><tr><td>肥料成本支撐（下檔）</td><td>巴西大豐收 177.8M 噸</td></tr><tr><td>季節性偏多</td><td>美國擴種（玉米轉黃豆）</td></tr><tr><td>中國需求強勁（1.12 億噸）</td><td>中美貿易戰</td></tr><tr><td>尿素若突破 $700 → +8-15%</td><td>出口下修至 15.4 億蒲式耳</td></tr></tbody></table><h3 id="_5-3-交易策略" tabindex="-1">5.3 交易策略 <a class="header-anchor" href="#_5-3-交易策略" aria-label="Permalink to &quot;5.3 交易策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>策略</th><th>條件</th><th>目標</th></tr></thead><tbody><tr><td>區間操作</td><td>1,100-1,200</td><td>低買高賣</td></tr><tr><td>逢低佈局</td><td>1,100 以下</td><td>1,200（+9%）</td></tr><tr><td>突破追多</td><td>站穩 1,200</td><td>1,250-1,300</td></tr><tr><td>尿素追蹤</td><td>尿素突破 $700</td><td>買入黃豆期貨</td></tr></tbody></table><h3 id="_5-4-風險提示" tabindex="-1">5.4 風險提示 <a class="header-anchor" href="#_5-4-風險提示" aria-label="Permalink to &quot;5.4 風險提示&quot;">​</a></h3><ol><li><strong>天氣黑天鵝</strong>：美國/巴西極端天氣</li><li><strong>中美貿易戰</strong>：政策突變</li><li><strong>尿素閾值</strong>：突破 $700 後需立即重新評估</li><li><strong>荷莫茲海峽</strong>：封鎖將造成劇烈波動</li></ol><hr><h2 id="六、結論" tabindex="-1">六、結論 <a class="header-anchor" href="#六、結論" aria-label="Permalink to &quot;六、結論&quot;">​</a></h2><p><strong>黃豆期貨處於「供需偏鬆 + 成本支撐」的拉鋸格局。</strong></p><ul><li><strong>下檔支撐</strong>：肥料成本（盈虧平衡 $1,040）+ 中國需求</li><li><strong>上檔壓力</strong>：巴西豐收 + 美國擴種 + 貿易戰</li><li><strong>突破條件</strong>：尿素 $700+ 或美國天氣災害</li><li><strong>操作建議</strong>：區間操作為主，1,100 以下逢低佈局，1,200 以上獲利了結</li></ul><hr><p><em>本報告由 Gale 整合多路 Dr.32 深挖資料編纂。</em><em>資料截至 2026-04-27。免責聲明：僅供研究參考，不構成投資建議。</em></p>`,50)])])}const u=d(h,[["render",o]]);export{_ as __pageData,u as default};
